1	/** A live cell's coordinates as [x, y]. */
2	export type Cell = [number, number];
3	
4	/**
5	 * Returns the next generation of live cells per Conway's Game of Life rules.
6	 *
7	 * Rules:
8	 *  - Underpopulation: a live cell with fewer than 2 live neighbors dies.
9	 *  - Survival: a live cell with 2 or 3 live neighbors lives on.
10	 *  - Overpopulation: a live cell with more than 3 live neighbors dies.
11	 *  - Reproduction: a dead cell with exactly 3 live neighbors becomes alive.
12	 */
13	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
14	  [-1, -1], [-1, 0], [-1, 1],
15	  [ 0, -1],          [ 0, 1],
16	  [ 1, -1], [ 1, 0], [ 1, 1],
17	];
18	
19	const toKey = ([x, y]: Cell): string => `${x},${y}`;
20	
21	export function nextGeneration(liveCells: Cell[]): Cell[] {
22	  const liveSet = new Set(liveCells.map(toKey));
23	  const isAlive = (cell: Cell): boolean => liveSet.has(toKey(cell));
24	
25	  const neighborsOf = ([x, y]: Cell): Cell[] =>
26	    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
27	
28	  const countLiveNeighbors = (cell: Cell): number =>
29	    neighborsOf(cell).filter(isAlive).length;
30	
31	  const livesNextGeneration = (cell: Cell): boolean => {
32	    const liveNeighbors = countLiveNeighbors(cell);
33	    return isAlive(cell) ? liveNeighbors === 2 || liveNeighbors === 3 : liveNeighbors === 3;
34	  };
35	
36	  const candidates = new Map<string, Cell>();
37	  for (const cell of liveCells) {
38	    candidates.set(toKey(cell), cell);
39	    for (const neighbor of neighborsOf(cell)) {
40	      candidates.set(toKey(neighbor), neighbor);
41	    }
42	  }
43	
44	  return [...candidates.values()].filter(livesNextGeneration);
45	}
